const fs = require('fs');
const path = require('path');

const project = String.raw`C:\Users\sumit\OneDrive\Documents\GateAI\gateai-app`;

const files = {
  'favicon.ico': '',
  'icon-16.png': '',
  'icon-32.png': '',
  'icon-64.png': '',
  'icon-180.png': '',
  'icon-192.png': '',
  'icon-512.png': '',
};
const mappings = [
  ['favicon.ico',  path.join(project, 'app', 'favicon.ico')],
  ['favicon.ico',  path.join(project, 'public', 'favicon.ico')],
  ['icon-16.png',  path.join(project, 'public', 'favicon-16.png')],
  ['icon-32.png',  path.join(project, 'public', 'favicon-32.png')],
  ['icon-64.png',  path.join(project, 'public', 'logo-icon-64.png')],
  ['icon-180.png', path.join(project, 'public', 'logo-icon-180.png')],
  ['icon-192.png', path.join(project, 'public', 'logo-icon-192.png')],
  ['icon-512.png', path.join(project, 'public', 'logo-icon-512.png')],
  ['icon-512.png', path.join(project, 'public', 'logo-icon.png')],
];

for (const [src, dest] of mappings) {
  const buf = Buffer.from(files[src], 'base64');
  fs.writeFileSync(dest, buf);
  console.log('✓ Written:', dest);
}
console.log('Done!');
